@page "/settings"
@using sv_e11b8259ef584b82b502d1568e2b51a0.Components.Pages.SettingsSections
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h3 class="settings-sidebar-title">Settings</h3>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item">
                    <button class="settings-nav-link @(section == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section)">
                        <span class="settings-nav-icon">@GetSectionIcon(section)</span>
                        @section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    border: 1px solid #dee2e6;
}

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #fff;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #212529;
    border-bottom: 1px solid #eee;
}

.settings-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.settings-nav-item {
    padding: 0 0.5rem;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    width: 100%;
    padding: 0.65rem 1rem;
    border: none;
    background: none;
    border-radius: 6px;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: all 0.15s ease;
    text-align: left;
}

.settings-nav-link:hover {
    background: #f0f0f0;
    color: #212529;
}

.settings-nav-link.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.settings-nav-icon {
    font-size: 1.15rem;
    width: 1.5rem;
    text-align: center;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    background: #fff;
    overflow-y: auto;
}

