@using sv_e11b8259ef584b82b502d1568e2b51a0.Models
@using sv_e11b8259ef584b82b502d1568e2b51a0.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Profile</h2>
    <p class="section-description">Manage your personal information and public profile.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="text" class="form-control" value="@_avatarUrl" readonly />
                </div>
            </div>

            <div class="form-group">
                <label class="form-label" for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label class="form-label" for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_email" />
            </div>

            <div class="form-group">
                <label class="form-label" for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                    Discard Changes
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast-message toast-success">
                    ✅ Profile saved successfully!
                </div>
            }

            @if (_errorMessage is not null)
            {
                <div class="toast-message toast-error">
                    ❌ @_errorMessage
                </div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Last saved state for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _showSuccess = false;
        _errorMessage = null;
    }
}

