@using sv_e11b8259ef584b82b502d1568e2b51a0.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Security</h2>
    <p class="section-description">Manage your password, two-factor authentication, and active sessions.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="security-form">
            <!-- Change Password expandable panel -->
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordExpanded = !_passwordExpanded">
                    <span class="panel-title">🔑 Change Password</span>
                    <span class="panel-chevron @(_passwordExpanded ? "expanded" : "")">▶</span>
                </button>

                @if (_passwordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>

                        @if (_passwordError is not null)
                        {
                            <div class="toast-message toast-error">❌ @_passwordError</div>
                        }

                        @if (_passwordSuccess)
                        {
                            <div class="toast-message toast-success">✅ Password updated successfully!</div>
                        }

                        <button class="btn btn-primary mt-2" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                            @(_changingPassword ? "Updating..." : "Update Password")
                        </button>
                    </div>
                }
            </div>

            <!-- Two-factor authentication -->
            <div class="security-card">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Two-Factor Authentication</span>
                        <span class="toggle-hint">
                            @if (_twoFactorEnabled)
                            {
                                <span class="status-badge status-enabled">Enabled</span>
                            }
                            else
                            {
                                <span class="status-badge status-disabled">Disabled</span>
                            }
                        </span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_twoFactorEnabled" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                @if (_lastPasswordChange.HasValue)
                {
                    <div class="info-row">
                        <span class="info-label">Last password change:</span>
                        <span class="info-value">@_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</span>
                    </div>
                }
            </div>

            <!-- Active Sessions -->
            <div class="sessions-section">
                <h4 class="group-heading">Active Sessions</h4>

                <div class="sessions-table-container">
                    <table class="sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session != _sessions.FirstOrDefault())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="current-badge">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-overlay" @onclick="CancelRevoke">
                    <div class="modal-dialog" @onclick:stopPropagation>
                        <h4 class="modal-title">Revoke Session</h4>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <p class="modal-hint">This will sign out the device immediately.</p>
                        <div class="modal-actions">
                            <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking..." : "Revoke Session")
                            </button>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;

    // Password fields
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private bool _passwordSuccess;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = new List<ActiveSession>(settings.Sessions);
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _lastPasswordChange = DateTime.UtcNow;
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
        _sessionToRevoke = null;
        _revoking = false;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

