                        <span class="preview-dot yellow"></span>
                        <span class="preview-dot green"></span>
                        <span class="preview-title-bar">Application Preview</span>
                    </div>
                    <div class="preview-body" style="padding: @(_compactMode ? "0.5rem" : "1rem")">
