@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Notifications</h2>
    <p class="section-description">Choose how and when you want to be notified.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="notifications-form">
            <div class="toggle-group">
                <h4 class="group-heading">General</h4>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Email Notifications</span>
                        <span class="toggle-hint">Receive updates via email</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_emailNotifications" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Push Notifications</span>
                        <span class="toggle-hint">Receive push notifications in your browser</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_pushNotifications" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Weekly Digest</span>
                        <span class="toggle-hint">Get a summary of activity each week</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_weeklyDigest" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>
            </div>

            <div class="toggle-group">
                <h4 class="group-heading">Muted Channels</h4>
                <p class="group-hint">Check channels you want to mute.</p>

                <div class="channel-list">
                    @foreach (var channel in _allChannels)
                    {
                        <label class="channel-item">
                            <input type="checkbox"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                            <span class="channel-name">#@channel</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Preferences")
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast-message toast-success">
                    ✅ Notification preferences saved!
                </div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = new List<string>(prefs.MutedChannels);
        // Start with all channels muted as they come from the MutedChannels list
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
