{"file_text": "@using sv_e11b8259ef584b82b502d1568e2b51a0.Models
@using sv_e11b8259ef584b82b502d1568e2b51a0.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Appearance</h2>
    <p class="section-description">Customize how the application looks and feels.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme -->
            <div class="option-group">
                <h4 class="group-heading">Theme</h4>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-card @(_theme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span class="radio-card-icon">@GetThemeIcon(theme)</span>
                            <span class="radio-card-label">@theme</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="option-group">
                <h4 class="group-heading">Font Size</h4>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-card @(_fontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span class="radio-card-icon font-sample" style="font-size: @GetFontSampleSize(size)">Aa</span>
                            <span class="radio-card-label">@size</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="option-group">
                <h4 class="group-heading">Language</h4>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="option-group">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Compact Mode</span>
                        <span class="toggle-hint">Reduce spacing and padding for a denser layout</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_compactMode" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="option-group">
                <h4 class="group-heading">Preview</h4>
                <div class="preview-area @GetPreviewThemeClass()" style="@GetPreviewStyle()">
                    <div class="preview-header">
                        <span class="preview-dot red"></span>
                        <span class="preview-dot yellow"></span>
                        <span class="preview-dot green"></span>
                        <span class="preview-title-bar">Application Preview</span>
                    </div>
                    <div class="preview-body" style="padding: @(_compactMode ? "0.5rem" : "1rem")">
                        <h5 class="preview-heading">Dashboard</h5>
                        <p class="preview-text">This is a preview of your selected appearance settings.</p>
                        <div class="preview-cards">
                            <div class="preview-card">
                                <span class="preview-card-title">Tasks</span>
                                <span class="preview-card-value">12</span>
                            </div>
                            <div class="preview-card">
                                <span class="preview-card-title">Messages</span>
                                <span class="preview-card-value">5</span>
                            </div>
                        </div>
                        <button class="preview-button">Sample Button</button>
                    </div>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save")
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast-message toast-success">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private static string GetThemeIcon(string theme) => theme switch
    {
        "Light" => "☀️",
        "Dark" => "🌙",
        "System" => "💻",
        _ => "⚙️"
    };

    private static string GetFontSampleSize(string size) => size switch
    {
        "Small" => "0.85rem",
        "Medium" => "1rem",
        "Large" => "1.25rem",
        _ => "1rem"
    };

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewStyle()
    {
        var fs = _fontSize switch
        {
            "Small" => "13px",
            "Medium" => "15px",
            "Large" => "17px",
            _ => "15px"
        };
        return $"font-size: {fs}";
    }
}
