@using sv_e11b8259ef584b82b502d1568e2b51a0.Models
@using sv_e11b8259ef584b82b502d1568e2b51a0.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Notifications</h2>
    <p class="section-description">Choose how and when you want to be notified.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="notifications-form">
            <div class="toggle-group">
                <h4 class="group-heading">General</h4>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Email Notifications</span>
                        <span class="toggle-hint">Receive updates via email</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_emailNotifications" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Push Notifications</span>
                        <span class="toggle-hint">Receive push notifications in your browser</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_pushNotifications" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Weekly Digest</span>
                        <span class="toggle-hint">Get a summary of activity each week</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_weeklyDigest" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>
            </div>

