toolArgs.file_text:
.section-panel {
    max-width: 720px;
}

.section-title {
    font-size: 1.5rem;
    font-weight: 600;
    margin: 0 0 0.25rem;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    padding: 2rem;
    text-align: center;
    color: #6c757d;
}

.notifications-form {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.toggle-group {
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
}

.group-heading {
    font-size: 1rem;
    font-weight: 600;
    margin: 0 0 1rem;
    color: #212529;
}

.group-hint {
    font-size: 0.85rem;
    color: #6c757d;
    margin: -0.5rem 0 1rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    border-bottom: 1px solid #e9ecef;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.toggle-label {
    font-weight: 500;
    color: #212529;
}

.toggle-hint {
    font-size: 0.8rem;
    color: #6c757d;
}

/* Toggle switch styling */
.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    border-radius: 26px;
    transition: 0.25s;
}

.toggle-slider::before {
    position: absolute;
    content: "";
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    border-radius: 50%;
    transition: 0.25s;
}

.toggle-switch input:checked + .toggle-slider {
    background-color: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(22px);
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #e9ecef;
}

.channel-name {
    font-size: 0.9rem;
    color: #495057;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    padding-top: 0.5rem;
}

.toast-message {
    margin-top: 0.5rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
    animation: slideIn 0.3s ease;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

@keyframes slideIn {
    from { opacity: 0; transform: translateY(-8px); }
    to { opacity: 1; transform: translateY(0); }
}

