.section-panel {
    max-width: 720px;
}

.section-title {
    font-size: 1.5rem;
    font-weight: 600;
    margin: 0 0 0.25rem;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    padding: 2rem;
    text-align: center;
    color: #6c757d;
}

.security-form {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

/* Expandable panel */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.panel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 1rem 1.25rem;
    border: none;
    background: #f8f9fa;
    cursor: pointer;
    transition: background 0.15s;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-title {
    font-weight: 600;
    font-size: 1rem;
}

.panel-chevron {
    font-size: 0.75rem;
    transition: transform 0.2s;
    color: #6c757d;
}

.panel-chevron.expanded {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1.25rem;
    display: flex;
    flex-direction: column;
    gap: 1rem;
    border-top: 1px solid #dee2e6;
    animation: slideDown 0.2s ease;
}

@keyframes slideDown {
    from { opacity: 0; max-height: 0; }
    to { opacity: 1; max-height: 500px; }
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-label {
    font-weight: 500;
    font-size: 0.9rem;
    color: #495057;
}

.mt-2 {
    margin-top: 0.5rem;
}

/* Security card */
.security-card {
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.toggle-info {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
}

.toggle-label {
    font-weight: 600;
    color: #212529;
}

.toggle-hint {
    font-size: 0.85rem;
}

.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
}

.status-enabled {
    background: #d1e7dd;
    color: #0f5132;
}

.status-disabled {
    background: #f8d7da;
    color: #842029;
}

.info-row {
    margin-top: 1rem;
    padding-top: 0.75rem;
    border-top: 1px solid #dee2e6;
    font-size: 0.9rem;
    display: flex;
    gap: 0.5rem;
}

.info-label {
    color: #6c757d;
}

.info-value {
    font-weight: 500;
}

/* Toggle switch */
.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    border-radius: 26px;
    transition: 0.25s;
}

.toggle-slider::before {
    position: absolute;
    content: "";
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    border-radius: 50%;
    transition: 0.25s;
}

.toggle-switch input:checked + .toggle-slider {
    background-color: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(22px);
}

/* Sessions table */
.sessions-section {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
}

.group-heading {
    font-size: 1rem;
    font-weight: 600;
    margin: 0 0 1rem;
}

.sessions-table-container {
    overflow-x: auto;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
}

.sessions-table th {
    text-align: left;
    padding: 0.6rem 0.75rem;
    font-size: 0.8rem;
    text-transform: uppercase;
    color: #6c757d;
    border-bottom: 2px solid #dee2e6;
    font-weight: 600;
    letter-spacing: 0.03em;
}

.sessions-table td {
    padding: 0.75rem;
    border-bottom: 1px solid #eee;
    font-size: 0.9rem;
}

.sessions-table tr:last-child td {
    border-bottom: none;
}

.current-badge {
    display: inline-block;
    padding: 0.2rem 0.6rem;
    background: #cfe2ff;
    color: #084298;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
}

/* Modal */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
    animation: fadeIn 0.15s ease;
}

.modal-dialog {
    background: white;
    border-radius: 12px;
    padding: 1.5rem;
    max-width: 440px;
    width: 90%;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

.modal-title {
    margin: 0 0 0.75rem;
    font-size: 1.15rem;
}

.modal-hint {
    font-size: 0.85rem;
    color: #6c757d;
}

.modal-actions {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    margin-top: 1rem;
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

.toast-message {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

