toolArgs.file_text:
@using sv_e11b8259ef584b82b502d1568e2b51a0.Models
@using sv_e11b8259ef584b82b502d1568e2b51a0.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h2 class="section-title">Appearance</h2>
    <p class="section-description">Customize how the application looks and feels.</p>

    @if (_loading)
    {
        <div class="loading-spinner">Loading...</div>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme -->
            <div class="option-group">
                <h4 class="group-heading">Theme</h4>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-card @(_theme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span class="radio-card-icon">@GetThemeIcon(theme)</span>
                            <span class="radio-card-label">@theme</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="option-group">
                <h4 class="group-heading">Font Size</h4>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-card @(_fontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span class="radio-card-icon font-sample" style="font-size: @GetFontSampleSize(size)">Aa</span>
                            <span class="radio-card-label">@size</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="option-group">
                <h4 class="group-heading">Language</h4>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="option-group">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Compact Mode</span>
                        <span class="toggle-hint">Reduce spacing and padding for a denser layout</span>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_compactMode" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="option-group">
                <h4 class="group-heading">Preview</h4>
                <div class="preview-area @GetPreviewThemeClass()" style="@GetPreviewStyle()">
                    <div class="preview-header">
                        <span class="preview-dot red"></span>
                        <span class="preview-dot yellow"></span>
                        <span class="preview-dot green"></span>
                        <span class="preview-title-bar">Application Preview</span>
                    </div>
                    <div class="preview-body" style="padding: @(_compactMode ? "0.5rem" : "1rem")">
                        <h5 class="preview-heading">Dashboard</h5>
                        <p class="preview-text">This is a preview of your selected appearance settings.</p>
                        <div class="preview-cards">
                            <div class="preview-card">
                                <span class="preview-card-title">Tasks</span>
                                <span class="preview-card-value">12</span>
                            </div>
                            <div class="preview-card">
                                <span class="preview-card-title">Messages</span>
                                <span class="preview-card-value">5</span>
                            </div>
                        </div>
                        <button class="preview-button">Sample Button</button>
                    </div>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save")
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast-message toast-success">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private static string GetThemeIcon(string theme) => theme switch
    {
        "Light" => "☀️",
        "Dark" => "🌙",
        "System" => "💻",
        _ => "⚙️"
    };

    private static string GetFontSampleSize(string size) => size switch
    {
        "Small" => "0.85rem",
        "Medium" => "1rem",
        "Large" => "1.25rem",
        _ => "1rem"
    };

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewStyle()
    {
        var fs = _fontSize switch
        {
            "Small" => "13px",
            "Medium" => "15px",
            "Large" => "17px",
            _ => "15px"
        };
        return $"font-size: {fs}";
    }
}

.section-panel {
    max-width: 720px;
}

.section-title {
    font-size: 1.5rem;
    font-weight: 600;
    margin: 0 0 0.25rem;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    padding: 2rem;
    text-align: center;
    color: #6c757d;
}

.appearance-form {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.option-group {
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
}

.group-heading {
    font-size: 1rem;
    font-weight: 600;
    margin: 0 0 1rem;
    color: #212529;
}

.radio-group {
    display: flex;
    gap: 0.75rem;
    flex-wrap: wrap;
}

.radio-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    padding: 1rem 1.5rem;
    border: 2px solid #dee2e6;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.15s ease;
    min-width: 100px;
}

.radio-card:hover {
    border-color: #adb5bd;
}

.radio-card.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-card input {
    display: none;
}

.radio-card-icon {
    font-size: 1.5rem;
}

.radio-card-icon.font-sample {
    font-weight: 600;
    color: #495057;
}

.radio-card-label {
    font-size: 0.9rem;
    font-weight: 500;
    color: #495057;
}

.form-select {
    max-width: 280px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    font-size: 0.95rem;
    background: white;
}

/* Toggle */
.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.toggle-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.toggle-label {
    font-weight: 500;
    color: #212529;
}

.toggle-hint {
    font-size: 0.8rem;
    color: #6c757d;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    border-radius: 26px;
    transition: 0.25s;
}

.toggle-slider::before {
    position: absolute;
    content: "";
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    border-radius: 50%;
    transition: 0.25s;
}

.toggle-switch input:checked + .toggle-slider {
    background-color: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(22px);
}

/* Preview */
.preview-area {
    border-radius: 8px;
    border: 1px solid #dee2e6;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-header {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.6rem 0.75rem;
    border-bottom: 1px solid;
}

.preview-light .preview-header {
    background: #f0f0f0;
    border-color: #dee2e6;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #313244;
}

.preview-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
}

.preview-dot.red { background: #ff5f57; }
.preview-dot.yellow { background: #febc2e; }
.preview-dot.green { background: #28c840; }

.preview-title-bar {
    margin-left: 0.5rem;
    font-size: 0.8rem;
    opacity: 0.7;
}

.preview-body {
    transition: padding 0.2s ease;
}

.preview-heading {
    margin: 0 0 0.5rem;
    font-weight: 600;
}

.preview-text {
    opacity: 0.8;
    margin-bottom: 1rem;
    line-height: 1.5;
}

.preview-cards {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.preview-card {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
    flex: 1;
}

.preview-light .preview-card {
    background: #f0f0f0;
}

.preview-dark .preview-card {
    background: #313244;
}

.preview-card-title {
    font-size: 0.75em;
    opacity: 0.7;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.preview-card-value {
    font-size: 1.3em;
    font-weight: 700;
}

.preview-button {
    padding: 0.4rem 1rem;
    border-radius: 6px;
    border: none;
    font-size: 0.85em;
    cursor: default;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: white;
}

.preview-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

/* Actions & toast */
.form-actions {
    display: flex;
    gap: 0.75rem;
    padding-top: 0.5rem;
}

.toast-message {
    margin-top: 0.5rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
    animation: slideIn 0.3s ease;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

@keyframes slideIn {
    from { opacity: 0; transform: translateY(-8px); }
    to { opacity: 1; transform: translateY(0); }
}

