+    width: 20px;
+    left: 3px;
+    bottom: 3px;
+    background-color: white;
+    border-radius: 50%;
+    transition: 0.25s;
+}
+
+.toggle-switch input:checked + .toggle-slider {
+    background-color: #0d6efd;
+}
+
+.toggle-switch input:checked + .toggle-slider::before {
+    transform: translateX(22px);
+}
+
+/* Preview */
+.preview-area {
+    border-radius: 8px;
+    border: 1px solid #dee2e6;
+    overflow: hidden;
+    transition: all 0.3s ease;
+}
+
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+}
+
+.preview-header {
+    display: flex;
+    align-items: center;
+    gap: 0.4rem;
+    padding: 0.6rem 0.75rem;
+    border-bottom: 1px solid;
+}
+
+.preview-light .preview-header {
+    background: #f0f0f0;
+    border-color: #dee2e6;
+}
+
+.preview-dark .preview-header {
+    background: #181825;
+    border-color: #313244;
+}
+
+.preview-dot {
+    width: 10px;
+    height: 10px;
+    border-radius: 50%;
+}
+
+.preview-dot.red { background: #ff5f57; }
+.preview-dot.yellow { background: #febc2e; }
+.preview-dot.green { background: #28c840; }
+
+.preview-title-bar {
+    margin-left: 0.5rem;
+    font-size: 0.8rem;
+    opacity: 0.7;
+}
+
+.preview-body {
+    transition: padding 0.2s ease;
+}
+
+.preview-heading {
+    margin: 0 0 0.5rem;
+    font-weight: 600;
+}
+
+.preview-text {
+    opacity: 0.8;
+    margin-bottom: 1rem;
+    line-height: 1.5;
+}
+
+.preview-cards {
+    display: flex;
+    gap: 0.75rem;
+    margin-bottom: 1rem;
+}
+
+.preview-card {
+    padding: 0.75rem 1rem;
+    border-radius: 6px;
+    display: flex;
+    flex-direction: column;
+    gap: 0.2rem;
+    flex: 1;
+}
+
+.preview-light .preview-card {
+    background: #f0f0f0;
+}
+
+.preview-dark .preview-card {
+    background: #313244;
+}
+
+.preview-card-title {
+    font-size: 0.75em;
+    opacity: 0.7;
+    text-transform: uppercase;
+    letter-spacing: 0.05em;
+}
+
+.preview-card-value {
+    font-size: 1.3em;
+    font-weight: 700;
+}
+
+.preview-button {
+    padding: 0.4rem 1rem;
+    border-radius: 6px;
+    border: none;
+    font-size: 0.85em;
+    cursor: default;
+}
+
+.preview-light .preview-button {
+    background: #0d6efd;
+    color: white;
+}
+
+.preview-dark .preview-button {
+    background: #89b4fa;
+    color: #1e1e2e;
+}
+
+/* Actions & toast */
+.form-actions {
+    display: flex;
+    gap: 0.75rem;
+    padding-top: 0.5rem;
+}
+
+.toast-message {
+    margin-top: 0.5rem;
+    padding: 0.75rem 1rem;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    animation: slideIn 0.3s ease;
+}
+
+.toast-success {
+    background: #d1e7dd;
+    color: #0f5132;
+    border: 1px solid #badbcc;
+}
+
+@keyframes slideIn {
+    from { opacity: 0; transform: translateY(-8px); }
+    to { opacity: 1; transform: translateY(0); }
+}
+

